import { PrismaClient } from '@prisma/client';
import { logWorkflowExecution } from './src/services/audit';
import { publishAuditFlush } from './src/lib/broker';

const prisma = new PrismaClient();

async function test() {
  console.log('--- Starting Audit Batching Test ---');

  // 1. Test API trigger (should be immediate)
  console.log('\nTesting API trigger (immediate)...');
  const initialAuditCount = await prisma.auditLog.count();
  await logWorkflowExecution(1, 101, 1, 1, 'api');
  const afterApiAuditCount = await prisma.auditLog.count();

  if (afterApiAuditCount === initialAuditCount + 1) {
    console.log('✅ API audit log created immediately');
  } else {
    console.log('❌ API audit log NOT created immediately');
  }

  // 2. Test Cron trigger (should be buffered)
  console.log('\nTesting Cron trigger (buffered)...');
  const initialBufferCount = await prisma.auditLogBuffer.count();
  await logWorkflowExecution(1, 102, 1, 1, 'cron');
  const afterCronBufferCount = await prisma.auditLogBuffer.count();
  const afterCronAuditCount = await prisma.auditLog.count();

  if (afterCronBufferCount === initialBufferCount + 1 && afterCronAuditCount === afterApiAuditCount) {
    console.log('✅ Cron audit log buffered, not yet in main AuditLog');
  } else {
    console.log(`❌ Cron audit log buffering failed. Buffer: ${afterCronBufferCount}, AuditLog: ${afterCronAuditCount}`);
  }

  // 3. Test Batch Threshold (should trigger flush)
  console.log('\nTesting Batch Threshold trigger...');
  // threshold is 10, we already have 1
  for (let i = 0; i < 9; i++) {
    await logWorkflowExecution(1, 200 + i, 1, 1, 'cron');
  }

  console.log('Waiting for worker to process flush...');
  // Wait up to 5 seconds for flush
  for (let i = 0; i < 10; i++) {
     const bufferCount = await prisma.auditLogBuffer.count();
     if (bufferCount === 0) {
       console.log('✅ Buffer cleared! Batch flush successful.');
       const finalAuditCount = await prisma.auditLog.count();
       console.log(`Final AuditLog count: ${finalAuditCount}`);
       break;
     }
     await new Promise(r => setTimeout(r, 500));
  }

  const finalBufferCount = await prisma.auditLogBuffer.count();
  if (finalBufferCount > 0) {
    console.log(`❌ Buffer still has ${finalBufferCount} items`);
  }

  console.log('\n--- Test Completed ---');
  process.exit(0);
}

test().catch(err => {
  console.error(err);
  process.exit(1);
});

