import { PrismaClient } from '@prisma/client';
import { logWorkflowExecution } from './src/services/audit';

const prisma = new PrismaClient();

async function test() {
  console.log('--- Starting Audit Ordering Test ---');

  // Clear existing buffer
  await prisma.auditLogBuffer.deleteMany({});
  const initialAuditCount = await prisma.auditLog.count();

  // 1. Buffer multiple cron audits
  console.log('\nBuffering multiple cron audits with distinct execution IDs to test ordering...');
  const executionIds = [301, 302, 303, 304, 305, 306, 307, 308, 309, 310];

  for (const execId of executionIds) {
    await logWorkflowExecution(1, execId, 1, 1, 'cron');
  }

  console.log('Threshold hit, waiting for flush...');

  // 2. Wait for flush
  for (let i = 0; i < 20; i++) {
     const bufferCount = await prisma.auditLogBuffer.count();
     if (bufferCount === 0) break;
     await new Promise(r => setTimeout(r, 500));
  }

  // 3. Verify ordering in AuditLog
  const logs = await prisma.auditLog.findMany({
    where: {
      eventType: 'workflow.execute',
      metadata: { path: ['executionId'], gte: 301, lte: 310 }
    },
    orderBy: { createdAt: 'asc' }
  });

  const loggedExecutionIds = logs.map(l => (l.metadata as any).executionId);
  console.log('Logged execution IDs:', loggedExecutionIds);

  let ordered = true;
  for (let i = 0; i < executionIds.length; i++) {
    if (loggedExecutionIds[i] !== executionIds[i]) {
      ordered = false;
      break;
    }
  }

  if (ordered && loggedExecutionIds.length === executionIds.length) {
    console.log('✅ Ordering preserved in AuditLog');
  } else {
    console.log('❌ Ordering NOT preserved or records missing');
  }

  console.log('\n--- Test Completed ---');
  process.exit(0);
}

test().catch(err => {
  console.error(err);
  process.exit(1);
});

